The mandatory two-condition check (Stage 4):
c
size_t root_len = strlen(doc_root);  /* = 13 for "/var/www/html" /
if (strncmp(canonical, doc_root, root_len) != 0 ||
(canonical[root_len] != '/' && canonical[root_len] != '\0')) {
send_403(client_fd);   / covers Case 2 /
return;
}
/ Only Cases 1 and 3 reach here */
